    const prefixSum = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    // Precompute left increasing segments
    const leftInc = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1] + 1;
        } else {
            leftInc[i] = 0;
        }
    }

    // Precompute right increasing segments
    const rightInc = new Array(n).fill(0);
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 0;
        }
    }

    // Precompute left peaks (p) where nums[p] is the peak of the left increasing segment
    const leftPeak = new Array(n).fill(-1);
    for (let i = 1; i < n; i++) {
        if (leftInc[i] > 0) {
            leftPeak[i] = i - 1;
        } else if (i > 0) {
            leftPeak[i] = leftPeak[i - 1];
        }
    }

    // Precompute right peaks (q) where nums[q] is the trough before the right increasing segment
    const rightPeak = new Array(n).fill(-1);
    for (let i = n - 2; i >= 0; i--) {
        if (rightInc[i] > 0) {
            rightPeak[i] = i + 1;
        } else if (i < n - 1) {
            rightPeak[i] = rightPeak[i + 1];
        }
    }

    // Iterate through possible p and q positions
    for (let p = 1; p < n - 2; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check if p is a valid peak for left increasing segment
            const l = leftPeak[p];
            if (l === -1 || l >= p) continue;

            // Check if q is a valid trough before right increasing segment
            const r = rightPeak[q];
            if (r === -1 || r <= q) continue;

            // Ensure the segments are strictly increasing/decreasing
            // Check nums[l..p] is strictly increasing
            let validLeft = true;
            for (let i = l + 1; i <= p; i++) {
                if (nums[i] <= nums[i - 1]) {
                    validLeft = false;
                    break;
                }
            }
            if (!validLeft) continue;

            // Check nums[p..q] is strictly decreasing
            let validMiddle = true;
            for (let i = p + 1; i <= q; i++) {
                if (nums[i] >= nums[i - 1]) {
                    validMiddle = false;
                    break;
                }
            }
            if (!validMiddle) continue;

            // Check nums[q..r] is strictly increasing
            let validRight = true;
            for (let i = q + 1; i <= r; i++) {
                if (nums[i] <= nums[i - 1]) {
                    validRight = false;
                    break;
                }
            }
            if (!validRight) continue;

            // Calculate the sum from l to r
            const currentSum = prefixSum[r + 1] - prefixSum[l];
            if (currentSum > maxSum) {
