            rightInc[i] = rightInc[i + 1] + 1;
        } else {
            rightInc[i] = 0;
        }
    }

    // Precompute left peaks (p) where left is increasing and right is decreasing
    const leftPeak = new Array(n).fill(false);
    for (let i = 1; i < n - 1; i++) {
