            rightPeak[i] = true;
        }
    }

    // Iterate all possible p and q to find valid l and r
    for (let p = 1; p < n - 2; p++) {
        if (!leftPeak[p]) continue;
        for (let q = p + 1; q < n - 1; q++) {
            if (!rightPeak[q]) continue;
            // Find the maximum l <= p where leftInc[p] >= p - l
            const minL = p - leftInc[p];
            // Find the maximum r >= q where rightInc[q] >= r - q
            const maxR = q + rightInc[q + 1] + 1;
